namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    // Split on sentence-ending punctuation followed by whitespace or end-of-string.
    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    private static readonly char[] WordSeparators = [' ', '\t', '\n', '\r'];

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency
    /// and returning the top-ranked sentences in their original order.
    /// </summary>
    public SummarizeResult Summarize(string text, int maxSentences)
    {
        var sentences = SentenceSplitter()
            .Split(text.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResult
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        // Build word-frequency map (case-insensitive, ignore short words).
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (word.Length <= 2) continue;
                wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
            }
        }

        // Score each sentence by summing its word frequencies.
        var scored = sentences
            .Select((sentence, index) => new
            {
                Sentence = sentence,
                Index = index,
                Score = GetWords(sentence)
                    .Where(w => w.Length > 2)
                    .Sum(w => wordFrequency.GetValueOrDefault(w))
            })
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        var summary = string.Join(" ", scored);

        return new SummarizeResult
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = maxSentences
        };
    }

    private static string[] GetWords(string sentence) =>
        sentence.Split(WordSeparators, StringSplitOptions.RemoveEmptyEntries);
}

public class SummarizeResult
{
    public required string Summary { get; init; }
    public int OriginalSentenceCount { get; init; }
    public int SummarySentenceCount { get; init; }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer;

    public SummarizeController(DocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest(new { error = "DocumentText must not be empty." });

        if (request.MaxSentences < 1)
            return BadRequest(new { error = "MaxSentences must be at least 1." });

        var result = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = result.Summary,
            OriginalSentenceCount = result.OriginalSentenceCount,
            SummarySentenceCount = result.SummarySentenceCount
        });
    }
}

